// ═══════════════════════════════════════════════════════════════
// PrepareData - استخراج والتحقق من البيانات
// 🔐 التوكن يُقرأ من n8n Credentials (أمان أعلى)
// ═══════════════════════════════════════════════════════════════
const inputData = $input.first().json;
const data = inputData.body || inputData;

// التحقق من البيانات المطلوبة (بدون accessToken - يُقرأ من Credentials)
const templateType = data.templateType;
const recipients = data.recipients || [];
const phoneNumberId = data.phoneNumberId || '';

if (!templateType) {
  return [{ json: { success: false, error: 'templateType مطلوب', hasError: true } }];
}
if (!phoneNumberId) {
  return [{ json: { success: false, error: 'phoneNumberId مطلوب', hasError: true } }];
}
if (!recipients || recipients.length === 0) {
  return [{ json: { success: false, error: 'recipients مطلوبة', hasError: true } }];
}

const defaultValues = {
  contactNumbers: data.contactNumbers || '07705210210',
  location: data.location || 'شركة الصدارة المشغل الرسمي للمشروع الوطني https://maps.app.goo.gl/LvgqPrKt2R4f3KFP6',
  offerText: data.offerText || 'لدينا عروض مميزة لك!'
};

const config = {
  maxRetries: data.maxRetries || 3,
  progressUpdateEvery: data.progressUpdateEvery || 100
};

const batchId = `batch_${Date.now()}`;
const total = recipients.length;

return recipients.map((r, index) => {
  let phone = (r.phoneNumber || r.phone || '').toString().trim();
  if (phone.startsWith('0')) {
    phone = '964' + phone.substring(1);
  } else if (!phone.startsWith('964') && !phone.startsWith('+964')) {
    phone = '964' + phone;
  }
  phone = phone.replace('+', '').replace(/[^\d]/g, '');

  const valid = /^964\d{9,12}$/.test(phone);

  return {
    json: {
      index: index + 1,
      total: total,
      batchId: batchId,
      name: r.name || 'عزيزي المشترك',
      phone: phone,
      originalPhone: r.phoneNumber || r.phone || '',
      expiryDate: r.expiryDate || r.expires || '',
      planName: r.planName || r.plan || '',
      price: r.price || '',
      templateType: templateType,
      phoneNumberId: phoneNumberId,
      contactNumbers: r.contactNumbers || defaultValues.contactNumbers,
      location: r.location || defaultValues.location,
      offerText: r.offerText || defaultValues.offerText,
      valid: valid,
      err: valid ? '' : 'Invalid phone format',
      hasError: false,
      retryCount: 0,
      config: config
    }
  };
});

// تجهيز الرد الفوري
const items = $items('PrepareData').map(i => i.json);
const first = items[0] || {};

if (first.hasError) {
  return [{
    json: {
      immediateResponse: {
        success: false,
        error: first.error
      },
      hasError: true
    }
  }];
}

const totalCount = items.length;
const batchId = first.batchId || `batch_${Date.now()}`;
const templateType = first.templateType || '';
const config = first.config || {};

return [{
  json: {
    immediateResponse: {
      success: true,
      status: 'processing',
      message: 'تم استلام الطلب وجاري إرسال الرسائل في الخلفية',
      batchId,
      templateType,
      totalRecipients: totalCount,
      estimatedTime: Math.ceil(totalCount * 1.5) + ' ثانية',
      features: {
        retryEnabled: true,
        maxRetries: config.maxRetries || 3,
        secureCredentials: true
      },
      timestamp: new Date().toISOString()
    },
    processItems: items,
    batchId,
    totalCount,
    config,
    hasError: false
  }
}];

// استخراج العناصر للمعالجة
const data = $json;
const items = data.processItems || [];
const config = data.config || {};
return items.map(item => ({ json: { ...item, config } }));

// تحضير بيانات القالب حسب النوع
const item = $input.first().json;
const templateType = item.templateType;

let templateName = '';
let components = [];
let messageText = '';

const name = item.name || 'عزيزي المشترك';
const expiryDate = item.expiryDate || '';
const planName = item.planName || '';
const price = item.price || '';
const contactNumbers = item.contactNumbers;
const location = item.location;
const offerText = item.offerText;

switch (templateType) {
  case 'sadara_reminder':
    templateName = 'sadara_reminder';
    components = [
      {
        "type": "header",
        "parameters": [
          {
            "type": "location",
            "location": {
              "latitude": "33.3574242",
              "longitude": "44.4413559",
              "name": "شركة الصدارة",
              "address": "المشغل الرسمي للمشروع الوطني"
            }
          }
        ]
      },
      {
        "type": "body",
        "parameters": [
          { "type": "text", "text": name },
          { "type": "text", "text": expiryDate },
          { "type": "text", "text": contactNumbers }
        ]
      }
    ];
    messageText = `شركة الصدارة للانترنت\n\nعزيزي المشترك ${name}،\nنود إعلامك بأن اشتراكك\nسينتهي بتاريخ ${expiryDate}\nجدد الآن لتجنب انقطاع الخدمة!\n\nالاتصال على\n${contactNumbers}`;
    break;

  case 'sadara_renewed':
    templateName = 'sadara_renewed';
    components = [
      {
        "type": "header",
        "parameters": [
          {
            "type": "location",
            "location": {
              "latitude": "33.3574242",
              "longitude": "44.4413559",
              "name": "شركة الصدارة",
              "address": "المشغل الرسمي للمشروع الوطني"
            }
          }
        ]
      },
      {
        "type": "body",
        "parameters": [
          { "type": "text", "text": name },
          { "type": "text", "text": planName },
          { "type": "text", "text": price.toString() },
          { "type": "text", "text": expiryDate },
          { "type": "text", "text": contactNumbers }
        ]
      }
    ];
    messageText = `مرحباً ${name} 🎉\n\nتم تجديد اشتراكك بنجاح!\n\nالباقة: ${planName}\nالمبلغ: ${price} د.ع\nتاريخ الانتهاء الجديد: ${expiryDate}\n\nللاستفسار:\n${contactNumbers}\n\n📍 ${location}`;
    break;

  case 'sadara_expired':
    templateName = 'sadara_expired';
    components = [
      {
        "type": "header",
        "parameters": [
          {
            "type": "location",
            "location": {
              "latitude": "33.3574242",
              "longitude": "44.4413559",
              "name": "شركة الصدارة",
              "address": "المشغل الرسمي للمشروع الوطني"
            }
          }
        ]
      },
      {
        "type": "body",
        "parameters": [
          { "type": "text", "text": name },
          { "type": "text", "text": offerText },
          { "type": "text", "text": contactNumbers }
        ]
      }
    ];
    messageText = `مرحباً ${name} 👋\n\نلاحظ أن اشتراكك قد انتهى بتاريخ ${expiryDate}.\n\n🎁 عرض خاص: ${offerText}\n\nللتجديد:\n${contactNumbers}\n\n📍 ${location}`;
    break;

  default:
    templateName = 'sadara_reminder';
    components = [
      {
        "type": "header",
        "parameters": [
          {
            "type": "location",
            "location": {
              "latitude": "33.3574242",
              "longitude": "44.4413559",
              "name": "شركة الصدارة",
              "address": "المشغل الرسمي للمشروع الوطني"
            }
          }
        ]
      },
      {
        "type": "body",
        "parameters": [
          { "type": "text", "text": name },
          { "type": "text", "text": expiryDate },
          { "type": "text", "text": contactNumbers }
        ]
      }
    ];
    messageText = `شركة الصدارة للانترنت\n\nعزيزي المشترك ${name}،\nنود إعلامك بأن اشتراكك\nسينتهي بتاريخ ${expiryDate}\nجدد الآن لتجنب انقطاع الخدمة!\n\nالاتصال على\n${contactNumbers}`;
}

return {
  index: item.index,
  total: item.total,
  batchId: item.batchId,
  phone: item.phone,
  name: name,
  templateType: templateType,
  templateName: templateName,
  components: components,
  messageText: messageText,
  phoneNumberId: item.phoneNumberId,
  expiryDate: expiryDate,
  planName: planName,
  price: price,
  retryCount: item.retryCount || 0,
  config: item.config
};

// ═══════════════════════════════════════════════════════════════
// ProcessResult - معالجة نتيجة الإرسال مع دعم Retry و Auth Error
// ═══════════════════════════════════════════════════════════════
const response = $input.first().json;
const templateData = $('BuildTemplate').first().json;
const config = templateData.config || {};
const maxRetries = config.maxRetries || 3;

let success = false;
let messageId = '';
let errorMessage = '';
let errorCode = '';
let shouldRetry = false;
let isAuthError = false;

if (response.body && response.body.messages && response.body.messages[0]) {
  success = true;
  messageId = response.body.messages[0].id;
} else if (response.body && response.body.error) {
  errorCode = response.body.error.code || '';
  errorMessage = response.body.error.message || 'Unknown error';

  // تصنيف الأخطاء
  const retryableCodes = [1, 2, 4, 17, 341, 368, 130429];
  const authErrorCodes = [190, 102, 104, 200];

  if (authErrorCodes.includes(Number(errorCode))) {
    isAuthError = true;
    errorMessage = '🔴 خطأ مصادقة - تحقق من WhatsApp Access Token في Credentials';
  } else if (retryableCodes.includes(Number(errorCode))) {
    shouldRetry = templateData.retryCount < maxRetries;
    errorMessage = `خطأ مؤقت (${errorCode}) - ${shouldRetry ? 'سيتم إعادة المحاولة' : 'استنفدت المحاولات'}`;
  } else {
    if (errorCode == 131030) errorMessage = 'رقم الهاتف غير صالح أو غير مسجل في WhatsApp';
    else if (errorCode == 131026) errorMessage = 'الرسالة لم تُرسل - تأكد من نافذة الـ 24 ساعة';
    else if (errorCode == 132000) errorMessage = 'عدد المتغيرات لا يتطابق مع القالب';
    else if (errorCode == 132001) errorMessage = 'القالب غير موجود أو غير معتمد';
  }
} else if (response.statusCode && response.statusCode !== 200) {
  errorMessage = `HTTP Error: ${response.statusCode}`;
  shouldRetry = templateData.retryCount < maxRetries && response.statusCode >= 500;
} else {
  errorMessage = 'No response from WhatsApp API';
  shouldRetry = templateData.retryCount < maxRetries;
}

const ts = Math.floor(Date.now() / 1000);
const tsMs = Date.now();
const msgId = messageId ? messageId.replace(/\//g, '_') : 'msg_' + ts + '_' + templateData.index;

console.log(`[${templateData.index}/${templateData.total}] Phone: ${templateData.phone}, Success: ${success}, Retry: ${templateData.retryCount}/${maxRetries}`);

return [{
  json: {
    index: templateData.index,
    total: templateData.total,
    batchId: templateData.batchId,
    ok: success,
    messageId: messageId,
    msgId: msgId,
    err: errorMessage,
    errorCode: errorCode,
    phone: templateData.phone,
    name: templateData.name,
    templateType: templateData.templateType,
    templateName: templateData.templateName,
    messageText: templateData.messageText,
    ts: ts,
    tsMs: tsMs,
    retryCount: templateData.retryCount,
    shouldRetry: shouldRetry && !success,
    isAuthError: isAuthError,
    config: config,
    phoneNumberId: templateData.phoneNumberId,
    components: templateData.components,
    expiryDate: templateData.expiryDate,
    planName: templateData.planName,
    price: templateData.price
  }
}];

// ═══════════════════════════════════════════════════════════════
// AuthErrorStop - إيقاف مبكر عند خطأ مصادقة
// ═══════════════════════════════════════════════════════════════
const data = $input.first().json;

console.log('🔴 AUTH ERROR DETECTED - STOPPING BATCH');
console.log('Batch ID:', data.batchId);
console.log('Stopped at message:', data.index, 'of', data.total);
console.log('💡 تأكد من صحة WhatsApp Access Token في Credentials');

return [{ json: {
  success: false,
  warning: '🔴 تم إيقاف الإرسال بسبب خطأ مصادقة! تحقق من WhatsApp Access Token في Credentials',
  batchId: data.batchId,
  total: data.total,
  sent: data.index - 1,
  failed: data.total - data.index + 1,
  stoppedAt: data.index,
  rate: data.total ? ((data.index - 1) / data.total * 100).toFixed(1) + '%' : '0%',
  completedAt: new Date().toISOString(),
  failedSummary: 'Auth Error: ' + data.err,
  earlyStop: true,
  earlyStopReason: 'AUTH_ERROR'
} }];

// تجهيز البيانات لإعادة المحاولة
const data = $input.first().json;
console.log(`🔄 Retry attempt ${data.retryCount + 1} for phone: ${data.phone}`);

return [{
  json: {
    index: data.index,
    total: data.total,
    batchId: data.batchId,
    phone: data.phone,
    name: data.name,
    templateType: data.templateType,
    templateName: data.templateName,
    components: data.components,
    messageText: data.messageText,
    phoneNumberId: data.phoneNumberId,
    expiryDate: data.expiryDate,
    planName: data.planName,
    price: data.price,
    retryCount: data.retryCount + 1,
    config: data.config
  }
}];

const d = $input.first().json;
const type = d.templateType || 'template';
const name = d.name || '';
const expiry = d.expiryDate || '';
const plan = d.planName || '';
const price = d.price || '';
const contact = d.contactNumbers || '07705210210';

let msg = '';
if (type === 'sadara_renewed') {
  msg = '\u0645\u0631\u062d\u0628\u0627\u064b ' + name + ' \ud83c\udf89\n\n\u062a\u0645 \u062a\u062c\u062f\u064a\u062f \u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u0628\u0646\u062c\u0627\u062d!\n\n\u0627\u0644\u0628\u0627\u0642\u0629: ' + plan + '\n\u0627\u0644\u0645\u0628\u0644\u063a: ' + price + ' \u062f.\u0639\n\u062a\u0627\u0631\u064a\u062e \u0627\u0644\u0627\u0646\u062a\u0647\u0627\u0621: ' + expiry + '\n\n\u0644\u0644\u0627\u0633\u062a\u0641\u0633\u0627\u0631:\n' + contact;
} else if (type === 'sadara_reminder') {
  msg = '\u0639\u0632\u064a\u0632\u064a \u0627\u0644\u0645\u0634\u062a\u0631\u0643 ' + name + '\n\u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u0633\u064a\u0646\u062a\u0647\u064a \u0628\u062a\u0627\u0631\u064a\u062e ' + expiry + '\n\u062c\u062f\u062f \u0627\u0644\u0622\u0646!\n\n\u0644\u0644\u0627\u062a\u0635\u0627\u0644:\n' + contact;
} else if (type === 'sadara_expired') {
  msg = '\u0639\u0632\u064a\u0632\u064a ' + name + '\n\u0627\u0634\u062a\u0631\u0627\u0643\u0643 \u0627\u0646\u062a\u0647\u0649.\n\n\u0644\u0644\u062a\u062c\u062f\u064a\u062f:\n' + contact;
} else {
  msg = '[' + type + '] ' + name;
}

return [{ json: {
  phone: d.phone,
  name: name,
  apiBody: { message: msg, type: 'template' }
} }];

// تمرير نتيجة النجاح
const d = $('ProcessResult').item.json;
return [{ json: { index: d.index, total: d.total, batchId: d.batchId, name: d.name, phone: d.phone, ok: true, err: '', msgId: d.msgId } }];

// تمرير نتيجة الفشل
const d = $input.first().json;
return [{ json: { index: d.index, total: d.total, batchId: d.batchId, name: d.name, phone: d.phone, ok: false, err: d.err, msgId: '' } }];

// نتيجة رقم غير صالح
const item = $input.first().json;
return [{ json: { index: item.index, total: item.total, batchId: item.batchId, name: item.name, phone: item.phone, ok: false, err: item.err || 'Invalid phone format', msgId: '' } }];

// تجميع النتائج النهائية
const all = $input.all();
const sent = [], failed = [];
let batchId = '';

for (const it of all) {
  const j = it.json;
  batchId = j.batchId || batchId;
  if (j.ok) sent.push({ index: j.index, phone: j.phone, name: j.name, msgId: j.msgId });
  else failed.push({ index: j.index, phone: j.phone, name: j.name, err: j.err });
}

const failRate = all.length ? (failed.length / all.length * 100) : 0;
let warning = '';
if (failRate === 100) warning = '🔴 فشل إرسال جميع الرسائل! تحقق من WhatsApp Credential';
else if (failRate > 50) warning = '🟡 نسبة فشل عالية! تحقق من تفاصيل الأخطاء';
else if (failRate > 20) warning = '🟠 بعض الرسائل فشلت - راجع التفاصيل';

const failedSummary = failed.slice(0, 10).map(f => f.phone + ':' + (f.err || 'err').substring(0, 30)).join(' | ');

return [{ json: {
  success: sent.length > 0,
  warning: warning,
  batchId: batchId,
  total: all.length,
  sent: sent.length,
  failed: failed.length,
  rate: all.length ? (sent.length/all.length*100).toFixed(1)+'%' : '0%',
  completedAt: new Date().toISOString(),
  failedSummary: failedSummary,
  details: { sent, failed }
} }];

// تسجيل النتيجة النهائية
const result = $('Summary').first().json;

console.log('═══════════════════════════════════════════════════');
console.log('   WhatsApp Templates - Secure Credentials');
console.log('═══════════════════════════════════════════════════');
console.log('Batch ID:', result.batchId);
console.log('Total:', result.total);
console.log('Sent:', result.sent);
console.log('Failed:', result.failed);
console.log('Success Rate:', result.rate);
if (result.warning) console.log('⚠️ Warning:', result.warning);
console.log('═══════════════════════════════════════════════════');

return [{ json: result }];
